"); if events.is_empty() { out.push_str("- El organismo respira sin sobresalto; Umbra conserva la forma.
"); } else { for event in events { out.push_str(&format!("- {}
", event)); } } out.push_str(&self.report()); out.push('
'); out.push_str(&self.subjective_continuity()); out }

